#include<iostream>#include<algorithm>#include<vector>#define ll long longusing namespace std;int main(){    ios_base::sync_with_stdio(false);       cin.tie(NULL);    int t;    cin>>t;    while(t--){        ll n,k,p,m;        cin>>n>>k>>p>>m;        vector<ll> a(n);                for(int i=0;i<n;i++){            cin>>a[i];        }        ll win_idx=p-1;        ll total_win=0;        while(true){            if(win_idx<k){                if(m>= a[win_idx]){                    total_win++;                    m-=a[win_idx];                     int win_val=a[win_idx];                     a.erase(a.begin()+win_idx);                     a.push_back(win_val);                     win_idx= n-1;                }                else{                    break;                }            }            else{                ll min_ele= a[0];                int min_idx=0;                for(int i=1;i<k;i++){                    if(a[i]<min_ele){                        min_ele=a[i];                        min_idx=i;                    }                }                if(m>= min_ele){                    m-=min_ele;;                    a.erase(a.begin()+min_idx);                    a.push_back(min_ele);                    win_idx--;                }                else{                    break;                }            }        }        cout<<total_win<<"\n";    }}